def _unpack_deps():
    if DEPS_DIR.exists():
        return
    import io
    raw = base64.b64decode(_BUNDLE.encode())
    DEPS_DIR.mkdir()
    with zipfile.ZipFile(io.BytesIO(raw)) as zf:
        zf.extractall(DEPS_DIR)

_unpack_deps()
if str(DEPS_DIR) not in sys.path:
    sys.path.insert(0, str(DEPS_DIR))

